import { glob } from 'glob';
import path from 'node:path';

import { execCommand } from '../utils/exec.js';

/**
 * Runs configured coverage commands sequentially so later commands can depend
 * on artifacts generated by earlier ones.
 */
export async function runCoverageCommands(
  repoPath: string,
  commands: string[],
  stage: 'unit' | 'e2e',
  options: {
    env?: Record<string, string>;
    timeoutMs?: number;
    allowFailure?: boolean;
  } = {},
): Promise<void> {
  if (commands.length === 0) {
    return;
  }

  for (const command of commands) {
    console.log(`[coverage:${stage}] ${command}`);
    const result = await execCommand(command, {
      cwd: repoPath,
      env: options.env,
      timeoutMs: options.timeoutMs,
    });
    if (result.exitCode !== 0) {
      if (options.allowFailure) {
        console.warn(
          `[coverage:${stage}] command failed but continuing because allowFailure=true: ${command}`,
        );
        continue;
      }
      throw new Error(`Coverage command failed (${stage}): ${command}\n${result.stderr}`);
    }
  }
}

/**
 * Resolves coverage profile globs relative to repository root.
 */
export async function collectCoverageProfiles(
  repoPath: string,
  profileGlobs: string[],
): Promise<string[]> {
  const profilePaths = new Set<string>();

  for (const pattern of profileGlobs) {
    const matches = await glob(pattern, {
      cwd: repoPath,
      absolute: true,
      nodir: true,
    });
    for (const match of matches) {
      profilePaths.add(path.resolve(match));
    }
  }

  const allProfiles = [...profilePaths];
  if (allProfiles.length === 0) {
    throw new Error(`No coverage profiles were found by patterns: ${profileGlobs.join(', ')}`);
  }
  return allProfiles;
}
